        public string OpenRecipeFileByPath()
        {
            if (!string.Equals(this.Enable, "Y", StringComparison.OrdinalIgnoreCase))
            {
                Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                    string.Format("[SKIP] Enable='{0}' — bo qua row nay.", this.Enable));
                return this.RecipeFilePath;
            }

            string recipeFilePath = this.RecipeFilePath;

            if (string.IsNullOrEmpty(recipeFilePath))
                throw new ArgumentException("RecipeFilePath khong duoc de trong.");

            if (!File.Exists(recipeFilePath))
                throw new FileNotFoundException(
                    string.Format("File khong ton tai: '{0}'", recipeFilePath), recipeFilePath);

            Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                string.Format("Target file: '{0}'", recipeFilePath));

            try
            {
                // --- Buoc 1: Click BtnOpenFileFromProduction ---
                Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                    "Buoc 1: Click BtnOpenFileFromProduction...");
                repo.CCIMainWindow.Area1.BtnOpenFileFromProduction.Click();
                Delay.Milliseconds(500);

                // --- Buoc 2: Cho dialog xuat hien ---
                Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                    "Buoc 2: Cho dialog Select Recipe File...");
                if (!repo.SelectRecipeFile.SelfInfo.Exists(FILE_DIALOG_TIMEOUT_MS))
                {
                    Report.Screenshot(repo.CCIMainWindow.Self, true);
                    throw new Exception(
                        "Select Recipe File dialog khong xuat hien sau khi click BtnOpenFileFromProduction.");
                }
                Report.Log(ReportLevel.Success, "OpenFile_FromProduction",
                    "Buoc 2 OK: dialog xuat hien.");

                // --- Buoc 3: Nhap path ---
                Report.Log(ReportLevel.Info, "OpenFile_FromProduction", "Buoc 3: Nhap path...");
                EnterPathIntoFileNameField(recipeFilePath);

                // --- Buoc 4: Click Open ---
                Report.Log(ReportLevel.Info, "OpenFile_FromProduction", "Buoc 4: Click Open...");
                repo.BtnOpenInDialog.Click();
                Delay.Milliseconds(1000);

                // --- Buoc 5: Wait va Click Apply (robust fallback) ---
                Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                    "Buoc 5: Click Apply voi fallback...");
                ClickApplyWithFallback();

                // --- Buoc 6: Cho app load sau Apply ---
                Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                    "Buoc 6: Cho app load sau Apply...");
                Delay.Milliseconds(2000);

                // --- Buoc 7: Validate TopTextRecipeName chua ModelName ---
                Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                    "Buoc 7: Validate ModelName tai vung TOP...");
                ValidateTopModelName();
            }
            finally
            {
                CleanupDialog();
            }

            return this.RecipeFilePath;
        }

        private void EnterPathIntoFileNameField(string path)
        {
            repo.SelectRecipeFile.Self.Activate();
            Delay.Milliseconds(300);
            repo.SelectRecipeFile.Text1148.Click();
            Delay.Milliseconds(300);

            Report.Log(ReportLevel.Info, "OpenFile_FromProduction", "Set TextValue...");
            repo.SelectRecipeFile.Text1148.TextValue = path;
            Delay.Milliseconds(500);

            string fieldText = ReadFileNameField();
            Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                string.Format("Field text: '{0}'", fieldText));

            bool match = !string.IsNullOrEmpty(fieldText)
                && (fieldText.Equals(path, StringComparison.OrdinalIgnoreCase)
                    || path.EndsWith(fieldText, StringComparison.OrdinalIgnoreCase));

            if (!match)
                throw new Exception(string.Format(
                    "Khong the set path. Actual: '{0}', Expected: '{1}'", fieldText, path));

            Report.Log(ReportLevel.Success, "OpenFile_FromProduction",
                string.Format("Path set dung: '{0}'", fieldText));
        }

        private string ReadFileNameField()
        {
            try { return repo.SelectRecipeFile.Text1148.TextValue; }
            catch
            {
                try { return repo.SelectRecipeFile.Text1148.Element.GetAttributeValueText("WindowText"); }
                catch { return "(khong doc duoc)"; }
            }
        }

        private void ValidateTopModelName()
        {
            string expected = this.ModelName;

            if (string.IsNullOrEmpty(expected))
            {
                Report.Log(ReportLevel.Error, "OpenFile_FromProduction",
                    "ModelName is empty. Check ModeName -> ModelName binding in Ranorex Studio.");
                throw new Exception(
                    "ModelName is empty. Check ModeName -> ModelName binding in Ranorex Studio.");
            }

            Report.Log(ReportLevel.Info, "OpenFile_FromProduction",
                string.Format("Expected ModelName = '{0}'", expected));

            var sw = System.Diagnostics.Stopwatch.StartNew();
            string actualText = null;

            while (sw.ElapsedMilliseconds < TOP_VALIDATE_TIMEOUT_MS)
            {
                try
                {
                    if (repo.CCIMainWindow.Area1.TopTextRecipeNameInfo.Exists(0))
                    {
                        var el = repo.CCIMainWindow.Area1.TopTextRecipeName.Element;

                        actualText = el.GetAttributeValueText("Text");
                        if (string.IsNullOrEmpty(actualText))
                            actualText = el.GetAttributeValueText("SelectionText");

                        Report.Log(ReportLevel.Debug, "OpenFile_FromProduction",
                            string.Format("ValidateTop poll: Text='{0}' ({1}ms)",
                                actualText ?? "(null)", sw.ElapsedMilliseconds));

                        if (!string.IsNullOrEmpty(actualText) && actualText.Contains(expected))
                        {
                            sw.Stop();
                            Report.Log(ReportLevel.Success, "OpenFile_FromProduction",
                                string.Format("TOP ModelName matched: '{0}' contains '{1}' ({2}ms)",
                                    actualText, expected, sw.ElapsedMilliseconds));
                            return;
                        }
                    }
                }
                catch (Exception ex)
                {
                    Report.Log(ReportLevel.Debug, "OpenFile_FromProduction",
                        string.Format("ValidateTop poll exception: {0}", ex.Message));
                }

                Delay.Milliseconds(TOP_VALIDATE_POLL_MS);
            }

            sw.Stop();
            Report.Screenshot(repo.CCIMainWindow.Self, true);
            Report.Log(ReportLevel.Error, "OpenFile_FromProduction",
                string.Format("TOP ModelName FAIL. Expected contains: '{0}', Actual Text: '{1}' ({2}ms)",
                    expected, actualText ?? "(null)", sw.ElapsedMilliseconds));
            throw new Exception(string.Format(
                "ValidateTopModelName FAIL: TopTextRecipeName Text = '{0}', expected contains '{1}'",
                actualText ?? "(null)", expected));
        }

